+function runtimeReviewTextFromReport(markdown: string): string {
+  return runtimeReviewText({
+    model: frontMatterValue(markdown, "review_model") ?? "",
+    reasoningEffort: frontMatterValue(markdown, "review_reasoning_effort") ?? "",
+  });
+}
